def combinations(n, k):
    """
    Calculate number of combinations (n choose k).
    """
    if k > n:
        return 0
    result = 1
    for i in range(1, k + 1):
        result = result * (n - k + i) // i
    return result

def permutations(n, k):
    """
    Calculate number of permutations (n P k).
    """
    if k > n:
        return 0
    result = 1
    for i in range(n - k + 1, n + 1):
        result *= i
    return result
